{
  "integration_assessment": {
    "component_interactions": [
      {
        "from": "KYC Service",
        "to": "Onfido API",
        "status": "risk",
        "issue": "Synchronous, blocking dependency with no fallback. Onfido downtime directly becomes registration downtime. The team's internal SLA (99.95%) is mathematically impossible to meet when the critical-path dependency (Onfido) only guarantees 99.9%. Best-case compound availability: 99.85% (assuming KYC service itself is 99.95%), which violates the team's own SLA by ~4.4 hours/year."
      },
      {
        "from": "KYC Service",
        "to": "User Registration Flow",
        "status": "risk",
        "issue": "Registration is fully blocked until KYC completes. A 3s p99 from Onfido plus network overhead means users experience multi-second waits on the critical onboarding path. No async/queued option exists."
      }
    ],
    "contract_compliance": "Onfido API contract is respected (5s timeout > Onfido p99 of 3s, which is correct). However, no handling for Onfido API contract changes, deprecations, or version drift.",
    "data_flow_integrity": "Structured JSON logging is in place. KYC check results flow synchronously back to the registration path. No evidence of idempotency handling — if a user retries after a timeout, a duplicate Onfido check may be created and billed."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No mention of logging Onfido request/response correlation IDs for cross-system debugging",
        "No mention of logging the specific Onfido failure mode (timeout vs 5xx vs 4xx vs network error) — critical for distinguishing provider outage from bad input"
      ]
    },
    "metrics": {
      "coverage": "partial — good foundation but missing critical signals",
      "gaps": [
        "No error-rate metric broken down by failure type (onfido_timeout, onfido_5xx, onfido_4xx, network_error)",
        "No metric for circuit breaker state (because there is no circuit breaker)",
        "No metric for retry attempts (because there are no retries)",
        "No registration-funnel drop-off metric to quantify business impact of Onfido failures"
      ]
    },
    "tracing": {
      "coverage": "not mentioned",
      "gaps": [
        "No distributed tracing mentioned — cannot correlate a user's registration request through KYC service to Onfido and back",
        "At 3am, an on-call engineer seeing elevated 503s cannot trace whether the root cause is Onfido, network, or internal"
      ]
    },
    "debugging_capability": "Moderate. Structured logging and basic metrics exist, but the lack of distributed tracing and error-type breakdown means diagnosing whether a spike in 503s is caused by Onfido, network issues, or an internal bug requires manual log correlation. The /health endpoint checking Onfido reachability is good — it enables load balancers to route away from unhealthy instances — but it also means a healthy instance can still fail individual requests if Onfido is intermittently degraded."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Onfido full outage (minutes to hours)",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Implement a degraded mode. Options: (1) Accept registration and queue KYC check for async retry, marking user as 'pending_verification' with limited platform access. (2) Allow a configurable grace period where users can register but cannot transact until KYC completes. Either approach decouples registration availability from Onfido availability."
      },
      {
        "scenario": "Onfido intermittent degradation (elevated latency, partial errors)",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Add a circuit breaker (e.g., 50% error rate over 30s window → open circuit for 60s). Without it, every single request during degradation will wait up to 5s and fail, consuming threads/connections and potentially cascading to upstream services."
      },
      {
        "scenario": "Onfido timeout at 5s boundary",
        "handling": "partial",
        "recommendation": "Timeout is set (good), but no retry with backoff for transient failures. Add 1 retry with jitter for 5xx/timeout responses only (not for 4xx). This alone could recover ~50% of transient failures."
      },
      {
        "scenario": "User retries after registration failure",
        "handling": "unhandled",
        "recommendation": "Add idempotency key (e.g., user email or session ID) to Onfido requests. Without it, each retry creates a new billable Onfido check and may cause inconsistent state if the first request actually succeeded but the response was lost."
      },
      {
        "scenario": "Thread/connection pool exhaustion during Onfido slowdown",
        "handling": "unhandled",
        "recommendation": "With no circuit breaker and a 5s timeout, a sustained Onfido slowdown will hold all request threads for 5s each. At moderate traffic, this exhausts the connection pool and causes the entire KYC service to become unresponsive — not just for KYC, but for /health and any other endpoints. Add bulkhead isolation (separate thread pool for Onfido calls)."
      }
    ],
    "retry_config": "None configured. Should add 1 retry with exponential backoff + jitter for 5xx/timeout only.",
    "timeout_config": "5s timeout is reasonable given Onfido's 3s p99. However, consider a lower timeout (e.g., 4s) paired with a retry, so total worst-case is 8s but recovery from transient blips is automatic.",
    "circuit_breakers": "None. This is the single highest-priority gap. Without a circuit breaker, Onfido degradation becomes KYC service degradation becomes registration outage.",
    "graceful_degradation": "None. The service is binary: Onfido works → registration works, Onfido fails → registration fails. This is the architectural root cause of the SLA violation."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous container image. Adequate for code-level rollbacks. However, since the core issue is an external dependency (Onfido), rollback does not mitigate the primary risk — rolling back to the previous version still has the same Onfido dependency with no fallback.",
    "monitoring_coverage": "Basic metrics exist (kyc_checks_total, kyc_duration_histogram, /health). Missing: error-type breakdown, circuit breaker state, registration drop-off correlation, and alerting rules. Recommend alerts on: kyc_duration_histogram p99 > 4s, kyc error rate > 5% over 5m, /health failing for > 30s.",
    "on_call_documentation": "Not mentioned. On-call engineer needs a runbook covering: (1) How to verify if Onfido is the root cause, (2) How to check Onfido status page, (3) What manual mitigation exists (currently: none, which is the problem), (4) Escalation path to Onfido support.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [],
      "new_queues_topics": [
        "If async KYC fallback is implemented: a durable queue (e.g., SQS, RabbitMQ) for deferred KYC checks"
      ],
      "config_changes": [
        "Circuit breaker thresholds (error_rate_threshold, window_size, open_duration)",
        "Retry policy config (max_retries, backoff_base, jitter)",
        "Feature flag for degraded-mode activation"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": true,
      "large_table_impact": false,
      "details": "No database migrations mentioned. If async fallback is added, a 'pending_verification' user state will need a schema change."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "infrastructure_gap",
      "issue": "SLA is mathematically unachievable: team promises 99.95% but depends synchronously on Onfido's 99.9% with no fallback",
      "reason": "Compound availability (99.95% × 99.9% = 99.85%) falls short of the 99.95% target by ~4.4 hours/year. Without a degraded mode or async fallback, every minute of Onfido downtime is a minute of registration downtime. This is not a bug to fix — it is an architectural constraint that requires either (a) a fallback path, or (b) lowering the team's SLA commitment to ≤99.9%.",
      "routed_to": "MJ — architect must design the async fallback or degraded-mode pattern before this ships"
    },
    {
      "type": "infrastructure_gap",
      "issue": "No circuit breaker on the sole external dependency",
      "reason": "Without a circuit breaker, Onfido intermittent degradation (not even a full outage) can cascade into full KYC service unavailability via thread/connection pool exhaustion. This turns a partial provider issue into a total service outage — the blast radius is unbounded.",
      "routed_to": "Shaq — implement circuit breaker with configurable thresholds before production deployment"
    },
    {
      "type": "missing_observability",
      "issue": "No distributed tracing and no error-type breakdown in metrics",
      "reason": "When Onfido has an incident at 2am and 503s spike, the on-call engineer currently cannot distinguish between Onfido timeout, Onfido 5xx, network partition, or internal error without manually reading logs. Error-type labels on kyc_checks_total and request tracing are needed for operational triage.",
      "routed_to": "Shaq — add error_type label to kyc_checks_total metric and integrate distributed tracing"
    }
  ],

  "confidence": {
    "level": 90,
    "high_confidence_areas": [
      "SLA math: 99.95% is provably unachievable with a synchronous 99.9% dependency and no fallback",
      "Circuit breaker gap: well-understood failure mode with cascading risk",
      "Rollback limitation: redeploying previous image does not mitigate external dependency failures"
    ],
    "low_confidence_areas": [
      "Traffic volume unknown — thread exhaustion risk severity depends on concurrency levels",
      "Onfido's actual reliability vs their SLA — they may overperform, but designing to the SLA is correct",
      "Internal architecture details (thread pool sizes, connection limits) not provided"
    ],
    "assumptions": [
      "The KYC service has no other path to verify identity if Onfido is unavailable",
      "The 99.95% SLA is a hard business commitment, not aspirational",
      "No existing circuit breaker or retry logic exists beyond what was described",
      "The /health endpoint's Onfido reachability check is a simple ping, not a functional check"
    ]
  }
}

